CREATE TABLE conversation (id UUID PRIMARY KEY, tenant_id VARCHAR(128) NOT NULL, owner_subject_id VARCHAR(128) NOT NULL, title VARCHAR(255) NOT NULL, status VARCHAR(32) NOT NULL, pinned BOOLEAN NOT NULL DEFAULT FALSE, deleted_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL);
CREATE INDEX idx_conversation_tenant_updated ON conversation (tenant_id, updated_at DESC) WHERE deleted_at IS NULL;
CREATE TABLE message (id UUID PRIMARY KEY, tenant_id VARCHAR(128) NOT NULL, conversation_id UUID NOT NULL REFERENCES conversation(id), sequence BIGINT NOT NULL, sender_type VARCHAR(32) NOT NULL, sender_subject_id VARCHAR(128), message_type VARCHAR(32) NOT NULL, visibility VARCHAR(32) NOT NULL, content TEXT NOT NULL, status VARCHAR(32) NOT NULL, request_id UUID, metadata JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL, UNIQUE (tenant_id, conversation_id, sequence), UNIQUE (tenant_id, sender_subject_id, conversation_id, request_id));
CREATE TABLE conversation_outbox (event_id UUID PRIMARY KEY, tenant_id VARCHAR(128) NOT NULL, conversation_id UUID NOT NULL REFERENCES conversation(id), event_type VARCHAR(64) NOT NULL, event_version INTEGER NOT NULL, trace_id VARCHAR(128) NOT NULL, request_id UUID NOT NULL, payload JSONB NOT NULL, occurred_at TIMESTAMPTZ NOT NULL, published_at TIMESTAMPTZ, failure_diagnostic VARCHAR(1000), created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX idx_conversation_outbox_pending ON conversation_outbox (created_at) WHERE published_at IS NULL;
CREATE TABLE legacy_conversation_migration (legacy_conversation_id UUID PRIMARY KEY, tenant_id VARCHAR(128) NOT NULL, migrated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, source_name VARCHAR(128) NOT NULL);
CREATE TABLE legacy_message_migration (legacy_message_id UUID PRIMARY KEY, tenant_id VARCHAR(128) NOT NULL, migrated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, source_name VARCHAR(128) NOT NULL);
